module tb_top;
    logic clk_i  = 1'b0;
    logic rst_ni = 1'b0;
    always #5 clk_i = ~clk_i;
    initial begin
        repeat (4) @(posedge clk_i);
        rst_ni = 1'b1;
    end
    localparam int unsigned TIMEOUT_CYCLES = 100000;
    initial begin
