    string  scn_node0;  // node0 variant (low addr); drives node1.master
    string  scn_node1;  // node1 variant (high addr); drives node0.master
    longint unsigned router0_ctx, m0_ctx, s0_ctx, n0_nmu_ctx, n0_nsu_ctx;
    longint unsigned router1_ctx, m1_ctx, s1_ctx, n1_nmu_ctx, n1_nsu_ctx;

    initial begin
        if (!$value$plusargs("scenario_node0=%s", scn_node0) ||
            !$value$plusargs("scenario_node1=%s", scn_node1)) begin
            $display("ERROR: +scenario_node0=<path> +scenario_node1=<path> required");
            $finish(1);
        end
        cmodel_init(scn_node1);  // shared config; any variant is fine
        router0_ctx = cmodel_router_create("router_0", 0, 0, 2, 1, NUM_VC);
        router1_ctx = cmodel_router_create("router_1", 1, 0, 2, 1, NUM_VC);
        // node0.master -> node1-variant (dst coord 1); ejects at node1.NSU.
