        s1_ctx     = cmodel_slave_create ("slave_1",  scn_node1);
        n0_nmu_ctx = cmodel_nmu_create("nmu_0", 0, NUM_VC);  // src_id = node0 coord 0
        n0_nsu_ctx = cmodel_nsu_create("nsu_0", 0, NUM_VC);
        // node1.master -> node0-variant (dst coord 0); ejects at node0.NSU.
        m1_ctx     = cmodel_master_create("master_1", scn_node0);
