    axi_master_wrap #(
        .ID_WIDTH(ID_WIDTH), .ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)
    ) u_master_0 (
        .clk_i(clk_i), .rst_ni(rst_ni), .ctx_i(m0_ctx), .axi_o(master_nmu_axi_0.master)
    );

    axi_slave_wrap #(
        .ID_WIDTH(ID_WIDTH), .ADDR_WIDTH(ADDR_WIDTH), .DATA_WIDTH(DATA_WIDTH)
